import React, { useState, useEffect, useRef } from 'react';
import { createRoot } from 'react-dom/client';
import { GoogleGenAI } from "@google/genai";

// --- Constants & Curriculum Data ---

const WEEKS = [
  { id: 1, title: "Week 1: AI Awakening", color: "from-orange-400 to-red-500", icon: "fa-egg", description: "From Zero to Basic Concepts" },
  { id: 2, title: "Week 2: Machine Brains", color: "from-blue-400 to-indigo-500", icon: "fa-brain", description: "Neural Networks & Deep Learning" },
  { id: 3, title: "Week 3: The Transformer", color: "from-purple-400 to-pink-500", icon: "fa-robot", description: "Attention Is All You Need" },
  { id: 4, title: "Week 4: Prompt Magic", color: "from-green-400 to-emerald-600", icon: "fa-wand-magic-sparkles", description: "Mastering Communication" },
  { id: 5, title: "Week 5: Vision & Voice", color: "from-yellow-400 to-orange-500", icon: "fa-eye", description: "Multimodal AI" },
  { id: 6, title: "Week 6: AI Ethics", color: "from-cyan-400 to-blue-600", icon: "fa-scale-balanced", description: "Safety & Responsibility" },
  { id: 7, title: "Week 7: The Master", color: "from-slate-700 to-black", icon: "fa-dragon", description: "Final Project & Summoning" },
];

// Content for Week 1
const WEEK_1_CONTENT = [
  {
    day: 1,
    title: "What is AI?",
    shards: 1,
    steps: [
      { type: 'theory', content: "Welcome, apprentice! To summon the AI Dragon, you must understand its nature. Artificial Intelligence (AI) is simply a computer program that can perform tasks that typically require human intelligence, like seeing, hearing, or reasoning." },
      { type: 'quiz', question: "AI is best described as...", options: ["A magic spell", "A computer program mimicking human tasks", "A tiny robot in your phone"], correct: 1 },
      { type: 'theory', content: "AI isn't new! It started in the 1950s. But today, thanks to massive data and faster computers, it has 'awakened' into forms like ChatGPT and Gemini." },
      { type: 'quiz', question: "Why is AI powerful now?", options: ["We have more data and computing power", "Magic crystals", "Aliens helped us"], correct: 0 },
    ]
  },
  {
    day: 2,
    title: "ML vs Deep Learning",
    shards: 1,
    steps: [
      { type: 'theory', content: "Think of AI as the universe. Inside it is a galaxy called Machine Learning (ML) - computers learning from data without explicit programming. Inside ML is a solar system called Deep Learning (DL), inspired by the human brain." },
      { type: 'quiz', question: "Which is the correct hierarchy?", options: ["DL > ML > AI", "AI > ML > DL", "ML > AI > DL"], correct: 1 },
      { type: 'theory', content: "Classic ML is like teaching a computer to recognize a cat by saying 'it has whiskers'. Deep Learning is showing it 1,000 pictures of cats and letting it figure out the whiskers itself!" }
    ]
  },
  {
    day: 3,
    title: "Generative AI",
    shards: 1,
    steps: [
      { type: 'theory', content: "Traditional AI analyzes (e.g., 'Is this spam?'). Generative AI *creates* (e.g., 'Write a poem about spam'). It predicts the next piece of information based on what it has seen before." },
      { type: 'quiz', question: "What does Generative AI do?", options: ["Only sorts data", "Creates new content", "Deletes files"], correct: 1 }
    ]
  },
  {
    day: 4,
    title: "Large Language Models",
    shards: 1,
    steps: [
      { type: 'theory', content: "LLMs (Large Language Models) are the engines behind modern chatbots. They are trained on vast amounts of text from the internet to understand and generate human-like language." },
      { type: 'quiz', question: "What does LLM stand for?", options: ["Little Learning Machine", "Large Language Model", "Long Lasting Memory"], correct: 1 }
    ]
  },
  {
    day: 5,
    title: "Prompt Engineering",
    shards: 1,
    steps: [
      { type: 'theory', content: "The AI is a powerful genie, but you must wish carefully. 'Prompt Engineering' is the art of talking to the AI to get the best result. Be specific, give context, and assign a persona." },
      { type: 'quiz', question: "Which prompt is better?", options: ["Write a story.", "Write a funny 100-word story about a cat in space."], correct: 1 }
    ]
  },
  {
    day: 6,
    title: "AI Hallucinations",
    shards: 1,
    steps: [
      { type: 'theory', content: "Warning! AI can lie. Confidently. This is called 'hallucination'. Because it predicts the next word based on probability, it might invent facts that sound real but aren't." },
      { type: 'quiz', question: "If an AI sounds confident, it is...", options: ["Always right", "Possibly hallucinating", "A human in disguise"], correct: 1 }
    ]
  },
  {
    day: 7,
    title: "Week 1 Trial",
    shards: 1,
    isBoss: true,
    steps: [
      { type: 'theory', content: "You have trained for 6 days. Now, prove your knowledge to claim the Dragon Ball!" },
      { type: 'quiz', question: "What is the subset of Machine Learning inspired by the brain?", options: ["Deep Learning", "Shallow Learning", "Rocket Science"], correct: 0 },
      { type: 'quiz', question: "When AI invents false facts, it is called...", options: ["Dreaming", "Hallucination", "Creativity"], correct: 1 },
      { type: 'quiz', question: "To get better results from AI, you use...", options: ["Prompt Engineering", "Kind words only", "Binary code"], correct: 0 },
    ]
  }
];

// --- Sub-Components ---

const ProgressBar = ({ current, total }: { current: number, total: number }) => (
  <div className="w-full bg-gray-200 rounded-full h-3 mb-6">
    <div 
      className="bg-green-500 h-3 rounded-full transition-all duration-500" 
      style={{ width: `${(current / total) * 100}%` }}
    ></div>
  </div>
);

const ChatSensei = ({ context, onClose }: { context: string, onClose: () => void }) => {
  const [messages, setMessages] = useState<{role: 'user'|'model', text: string}[]>([
    { role: 'model', text: "I am your AI Sensei. Ask me anything about this lesson!" }
  ]);
  const [input, setInput] = useState("");
  const [loading, setLoading] = useState(false);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  };

  useEffect(scrollToBottom, [messages]);

  const handleSend = async () => {
    if (!input.trim() || loading) return;
    const userMsg = input;
    setMessages(prev => [...prev, { role: 'user', text: userMsg }]);
    setInput("");
    setLoading(true);

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      // Use standard content generation
      const response = await ai.models.generateContent({
        model: 'gemini-2.5-flash',
        contents: [
            {
                role: "user",
                parts: [{ text: `Context: You are a friendly, wise, and concise AI tutor for an app teaching AI to beginners. The current lesson content is: "${context}". The user asks: "${userMsg}". Answer briefly and encouragingly.` }]
            }
        ]
      });

      const text = response.text;
      setMessages(prev => [...prev, { role: 'model', text: text }]);
    } catch (e) {
      setMessages(prev => [...prev, { role: 'model', text: "My connection to the ether is weak. Please try again." }]);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="fixed inset-0 bg-black/50 z-50 flex items-end sm:items-center justify-center p-4">
      <div className="bg-white w-full max-w-md h-[80vh] rounded-2xl flex flex-col shadow-2xl overflow-hidden animate-bounce-slight" style={{animation: 'none'}}>
        <div className="bg-indigo-600 p-4 text-white flex justify-between items-center">
          <div className="flex items-center gap-2">
            <i className="fa-solid fa-robot text-xl"></i>
            <span className="font-bold">AI Sensei</span>
          </div>
          <button onClick={onClose} className="text-white/80 hover:text-white">
            <i className="fa-solid fa-xmark text-xl"></i>
          </button>
        </div>

        <div className="flex-1 overflow-y-auto p-4 space-y-4 bg-gray-50">
          {messages.map((m, i) => (
            <div key={i} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'}`}>
              <div className={`max-w-[80%] p-3 rounded-2xl ${
                m.role === 'user' 
                  ? 'bg-indigo-500 text-white rounded-tr-none' 
                  : 'bg-white border border-gray-200 text-gray-800 rounded-tl-none shadow-sm'
              }`}>
                {m.text}
              </div>
            </div>
          ))}
          {loading && (
             <div className="flex justify-start">
               <div className="bg-white border p-3 rounded-2xl rounded-tl-none">
                 <i className="fa-solid fa-circle-notch fa-spin text-indigo-500"></i> Thinking...
               </div>
             </div>
          )}
          <div ref={messagesEndRef} />
        </div>

        <div className="p-4 bg-white border-t flex gap-2">
          <input 
            type="text" 
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyDown={(e) => e.key === 'Enter' && handleSend()}
            placeholder="Ask about this lesson..."
            className="flex-1 border rounded-full px-4 py-2 focus:outline-none focus:ring-2 focus:ring-indigo-500"
          />
          <button 
            onClick={handleSend}
            disabled={loading}
            className="bg-indigo-600 text-white w-10 h-10 rounded-full flex items-center justify-center hover:bg-indigo-700 disabled:opacity-50"
          >
            <i className="fa-solid fa-paper-plane"></i>
          </button>
        </div>
      </div>
    </div>
  );
};

// --- Main Views ---

const WorldMap = ({ unlockedWeek, onSelectWeek, collectedBalls }: { unlockedWeek: number, onSelectWeek: (id: number) => void, collectedBalls: number }) => {
  return (
    <div className="flex flex-col items-center pb-20 pt-10 px-4 min-h-screen">
      <h1 className="text-3xl font-bold text-gray-800 mb-2">AI Mastery Path</h1>
      <div className="flex gap-4 mb-8 bg-white px-4 py-2 rounded-full shadow-sm">
        <div className="flex items-center gap-2 text-yellow-600 font-bold">
            <i className="fa-solid fa-dragon"></i> {collectedBalls}/7 Balls
        </div>
      </div>

      <div className="flex flex-col gap-8 w-full max-w-md relative">
        {/* Connecting Line */}
        <div className="absolute left-1/2 top-10 bottom-10 w-2 bg-gray-200 -translate-x-1/2 -z-10 rounded-full"></div>

        {WEEKS.map((week, index) => {
            const isUnlocked = week.id <= unlockedWeek;
            const isCompleted = week.id < unlockedWeek;

            return (
              <div 
                key={week.id} 
                onClick={() => isUnlocked && onSelectWeek(week.id)}
                className={`
                   relative flex flex-col items-center gap-2 cursor-pointer transition-transform hover:scale-105
                   ${index % 2 === 0 ? 'self-start ml-8' : 'self-end mr-8'}
                `}
              >
                 <div className={`
                    w-20 h-20 rounded-full flex items-center justify-center text-3xl shadow-lg border-4 
                    ${isUnlocked ? `bg-gradient-to-br ${week.color} border-white text-white` : 'bg-gray-300 border-gray-400 text-gray-500'}
                    ${isCompleted ? 'ring-4 ring-green-400' : ''}
                    btn-press
                 `}>
                    <i className={`fa-solid ${isUnlocked ? week.icon : 'fa-lock'}`}></i>
                 </div>
                 <div className="bg-white px-3 py-1 rounded-lg shadow-sm text-center min-w-[120px]">
                    <div className="font-bold text-sm text-gray-800">{week.title}</div>
                 </div>
              </div>
            );
        })}

        {/* Final Goal */}
        <div className="self-center mt-8 text-center opacity-50">
           <i className="fa-solid fa-crown text-4xl text-gray-400 mb-2"></i>
           <p className="text-xs font-bold text-gray-500">SUMMON DRAGON</p>
        </div>
      </div>
    </div>
  );
};

const WeekLevelView = ({ weekId, completedDays, onPlayDay, onBack }: { weekId: number, completedDays: number, onPlayDay: (day: number) => void, onBack: () => void }) => {
    const week = WEEKS.find(w => w.id === weekId);

    return (
        <div className="min-h-screen bg-[#3f64e7] relative overflow-hidden flex flex-col">
            <div className="p-4 text-white z-10 flex items-center gap-4">
                <button onClick={onBack} className="hover:bg-white/20 p-2 rounded-full transition"><i className="fa-solid fa-arrow-left"></i></button>
                <h2 className="text-xl font-bold">{week?.title}</h2>
            </div>

            <div className="flex-1 flex flex-col items-center justify-center relative pb-20">
                {/* Winding Path SVG Background or Logic could go here, simplified to vertical stack for reliability */}

                {WEEK_1_CONTENT.map((day, idx) => {
                    const isUnlocked = idx <= completedDays;
                    const isCompleted = idx < completedDays;
                    const isCurrent = idx === completedDays;

                    // Simple zig-zag layout
                    const offsetClass = idx % 2 === 0 ? '-translate-x-12' : 'translate-x-12';

                    return (
                        <div key={day.day} className={`relative my-4 transition-all duration-500 ${offsetClass}`}>
                            <button 
                                onClick={() => isUnlocked && onPlayDay(day.day)}
                                disabled={!isUnlocked}
                                className={`
                                    w-20 h-20 rounded-full border-b-8 flex items-center justify-center text-2xl shadow-xl transition-transform active:translate-y-1 active:border-b-0
                                    ${isCompleted ? 'bg-yellow-400 border-yellow-600 text-yellow-900' : ''}
                                    ${isCurrent ? 'bg-orange-500 border-orange-700 text-white animate-bounce-slight' : ''}
                                    ${!isUnlocked && !isCompleted ? 'bg-gray-400 border-gray-600 text-gray-200 cursor-not-allowed' : ''}
                                `}
                            >
                                {isCompleted ? <i className="fa-solid fa-check"></i> : 
                                 !isUnlocked ? <i className="fa-solid fa-lock"></i> :
                                 day.isBoss ? <i className="fa-solid fa-skull"></i> : 
                                 <i className="fa-solid fa-star"></i>}
                            </button>
                            <div className="absolute top-full mt-2 left-1/2 -translate-x-1/2 bg-black/40 text-white text-xs px-2 py-1 rounded whitespace-nowrap">
                                Day {day.day}
                            </div>
                        </div>
                    );
                })}
            </div>
        </div>
    );
};

const LessonEngine = ({ dayId, onComplete, onExit }: { dayId: number, onComplete: () => void, onExit: () => void }) => {
    const lesson = WEEK_1_CONTENT.find(d => d.day === dayId);
    const [stepIndex, setStepIndex] = useState(0);
    const [selectedOption, setSelectedOption] = useState<number | null>(null);
    const [showResult, setShowResult] = useState(false); // For quiz feedback
    const [isCorrect, setIsCorrect] = useState(false);
    const [showSensei, setShowSensei] = useState(false);

    if (!lesson) return <div>Loading...</div>;

    const currentStep = lesson.steps[stepIndex];
    const progress = stepIndex / lesson.steps.length;

    const handleContinue = () => {
        if (currentStep.type === 'quiz' && !showResult) {
            // Check answer
            if (selectedOption === null) return;
            const correct = selectedOption === currentStep.correct;
            setIsCorrect(correct);
            setShowResult(true);

            // Play sound effect (optional/simulated)
            if (!correct) return; // Don't advance if wrong? Or allow retry. 
            // Duolingo style: usually forces you to get it right or loops back.
            // For simplicity here, we allow proceeding but show red.
        } else {
            // Next step
            if (stepIndex < lesson.steps.length - 1) {
                setStepIndex(prev => prev + 1);
                setSelectedOption(null);
                setShowResult(false);
            } else {
                onComplete();
            }
        }
    };

    return (
        <div className="fixed inset-0 bg-white z-50 flex flex-col">
            {/* Header */}
            <div className="p-4 flex items-center gap-4">
                <button onClick={onExit} className="text-gray-400 hover:text-gray-600">
                    <i className="fa-solid fa-xmark text-2xl"></i>
                </button>
                <ProgressBar current={stepIndex + 1} total={lesson.steps.length} />
            </div>

            {/* Content Area */}
            <div className="flex-1 flex flex-col items-center justify-center p-6 max-w-2xl mx-auto w-full overflow-y-auto">

                {currentStep.type === 'theory' && (
                    <div className="text-center animate-bounce-slight" style={{animation: 'none'}}>
                        <h2 className="text-2xl font-bold mb-6 text-gray-800">New Concept</h2>
                        <div className="text-lg text-gray-600 leading-relaxed mb-8 border-l-4 border-orange-400 pl-4 text-left">
                            {currentStep.content}
                        </div>
                        <div className="text-6xl text-orange-400 mb-8">
                            <i className="fa-solid fa-lightbulb"></i>
                        </div>
                    </div>
                )}

                {currentStep.type === 'quiz' && (
                    <div className="w-full">
                        <h2 className="text-2xl font-bold mb-8 text-gray-800">{currentStep.question}</h2>
                        <div className="space-y-4">
                            {currentStep.options?.map((opt, idx) => (
                                <button
                                    key={idx}
                                    onClick={() => !showResult && setSelectedOption(idx)}
                                    className={`
                                        w-full p-4 rounded-xl border-2 text-left text-lg font-medium transition-all
                                        ${showResult && idx === currentStep.correct ? 'bg-green-100 border-green-500 text-green-700' : ''}
                                        ${showResult && idx === selectedOption && idx !== currentStep.correct ? 'bg-red-100 border-red-500 text-red-700' : ''}
                                        ${!showResult && selectedOption === idx ? 'bg-blue-100 border-blue-500 text-blue-700' : 'bg-white border-gray-200 hover:bg-gray-50'}
                                    `}
                                >
                                    {opt}
                                </button>
                            ))}
                        </div>
                    </div>
                )}

            </div>

            {/* AI Sensei Button */}
            <div className="absolute top-20 right-4">
                <button 
                  onClick={() => setShowSensei(true)}
                  className="bg-indigo-100 text-indigo-600 w-10 h-10 rounded-full flex items-center justify-center hover:bg-indigo-200 shadow-sm border border-indigo-200"
                  title="Ask AI Sensei"
                >
                    <i className="fa-solid fa-robot"></i>
                </button>
            </div>
            {showSensei && <ChatSensei context={currentStep.type === 'theory' ? currentStep.content : currentStep.question || ""} onClose={() => setShowSensei(false)} />}

            {/* Footer */}
            <div className={`p-4 border-t ${showResult ? (isCorrect ? 'bg-green-100 border-green-300' : 'bg-red-100 border-red-300') : 'bg-white'}`}>
                <div className="max-w-2xl mx-auto flex justify-between items-center">
                    {showResult && (
                        <div className="flex gap-3 items-center">
                            <div className={`w-10 h-10 rounded-full flex items-center justify-center text-white ${isCorrect ? 'bg-green-500' : 'bg-red-500'}`}>
                                <i className={`fa-solid ${isCorrect ? 'fa-check' : 'fa-xmark'}`}></i>
                            </div>
                            <div className={`font-bold ${isCorrect ? 'text-green-700' : 'text-red-700'}`}>
                                {isCorrect ? "Correct!" : "Not quite..."}
                            </div>
                        </div>
                    )}
                    <div className="flex-1"></div>
                    <button 
                        onClick={handleContinue}
                        disabled={currentStep.type === 'quiz' && !showResult && selectedOption === null}
                        className={`
                            px-8 py-3 rounded-xl font-bold text-white uppercase tracking-wide shadow-lg btn-press
                            ${showResult && !isCorrect ? 'bg-red-500 hover:bg-red-600' : 'bg-green-500 hover:bg-green-600'}
                            disabled:opacity-50 disabled:cursor-not-allowed
                        `}
                    >
                        {showResult && !isCorrect ? "Try Again" : "Continue"}
                    </button>
                </div>
            </div>
        </div>
    );
};

const RewardModal = ({ type, onClose }: { type: 'shard' | 'ball', onClose: () => void }) => {
    return (
        <div className="fixed inset-0 bg-black/80 z-[60] flex items-center justify-center p-4">
            <div className="bg-white rounded-3xl p-8 max-w-sm w-full text-center relative overflow-hidden">
                <div className="absolute top-0 left-0 w-full h-20 bg-gradient-to-b from-yellow-300 to-transparent opacity-50"></div>

                <h2 className="text-3xl font-bold text-yellow-600 mb-4 game-font">
                    {type === 'shard' ? "Shard Get!" : "DRAGON BALL!"}
                </h2>

                <div className="my-8 flex justify-center">
                    {type === 'shard' ? (
                        <div className="text-8xl text-orange-500 animate-bounce">
                           <i className="fa-solid fa-gem"></i>
                        </div>
                    ) : (
                        <div className="w-32 h-32 rounded-full bg-orange-500 border-4 border-yellow-300 shadow-[0_0_30px_rgba(255,165,0,0.6)] flex items-center justify-center text-5xl text-red-600 font-bold animate-spin" style={{animationDuration: '3s'}}>
                            <i className="fa-solid fa-star"></i>
                        </div>
                    )}
                </div>

                <p className="text-gray-600 mb-8">
                    {type === 'shard' 
                        ? "You earned a Dragon Shard! Collect 7 to forge a Dragon Ball." 
                        : "Amazing! You've mastered this week. One step closer to the Dragon!"}
                </p>

                <button 
                    onClick={onClose}
                    className="w-full py-4 rounded-xl bg-orange-500 text-white font-bold text-xl hover:bg-orange-600 btn-press"
                >
                    CLAIM
                </button>
            </div>
        </div>
    );
};

// --- App Container ---

const App = () => {
    // State
    const [view, setView] = useState<'map' | 'week' | 'lesson'>('map');
    const [activeWeek, setActiveWeek] = useState(1);
    const [activeDay, setActiveDay] = useState(1);

    // Progress persistence could be added with localStorage
    const [completedDays, setCompletedDays] = useState(0); // 0 to 7
    const [collectedShards, setCollectedShards] = useState(0);
    const [collectedBalls, setCollectedBalls] = useState(0);

    const [rewardQueue, setRewardQueue] = useState<('shard' | 'ball')[]>([]);

    const handleSelectWeek = (id: number) => {
        setActiveWeek(id);
        setView('week');
    };

    const handlePlayDay = (day: number) => {
        setActiveDay(day);
        setView('lesson');
    };

    const handleLessonComplete = () => {
        // Logic for completion
        const isNewCompletion = activeDay > completedDays;

        if (isNewCompletion) {
            setCompletedDays(prev => prev + 1);
            setCollectedShards(prev => prev + 1);
            setRewardQueue(prev => [...prev, 'shard']);

            // Check for week completion (7 days)
            if (activeDay === 7) {
                // Short delay for the second reward
                setTimeout(() => {
                    setCollectedBalls(prev => prev + 1);
                    setCollectedShards(0); // Reset shards? Or keep them. Usually convert.
                    setRewardQueue(prev => [...prev, 'ball']);
                }, 500);
            }
        }

        setView('week');
    };

    const handleCloseReward = () => {
        setRewardQueue(prev => prev.slice(1));
    };

    return (
        <div className="mx-auto max-w-md bg-gray-50 min-h-screen shadow-2xl overflow-hidden relative">
            {view === 'map' && (
                <WorldMap 
                    unlockedWeek={1 + Math.floor(collectedBalls)} // Simple logic: 1 ball unlocks week 2
                    collectedBalls={collectedBalls} 
                    onSelectWeek={handleSelectWeek} 
                />
            )}

            {view === 'week' && (
                <WeekLevelView 
                    weekId={activeWeek} 
                    completedDays={completedDays} // In a real app, this would be per-week
                    onPlayDay={handlePlayDay}
                    onBack={() => setView('map')}
                />
            )}

            {view === 'lesson' && (
                <LessonEngine 
                    dayId={activeDay}
                    onComplete={handleLessonComplete}
                    onExit={() => setView('week')}
                />
            )}

            {/* Bottom Nav (only on Map) */}
            {view === 'map' && (
                <div className="fixed bottom-0 left-0 right-0 bg-white border-t p-2 flex justify-around max-w-md mx-auto">
                    <button className="flex flex-col items-center p-2 text-orange-500">
                        <i className="fa-solid fa-map text-xl"></i>
                        <span className="text-xs font-bold">Learn</span>
                    </button>
                    <button className="flex flex-col items-center p-2 text-gray-400 hover:text-gray-600">
                         <i className="fa-solid fa-scroll text-xl"></i>
                        <span className="text-xs font-bold">Quests</span>
                    </button>
                    <button className="flex flex-col items-center p-2 text-gray-400 hover:text-gray-600">
                        <i className="fa-solid fa-user-ninja text-xl"></i>
                        <span className="text-xs font-bold">Profile</span>
                    </button>
                </div>
            )}

            {/* Rewards Overlay */}
            {rewardQueue.length > 0 && (
                <RewardModal type={rewardQueue[0]} onClose={handleCloseReward} />
            )}
        </div>
    );
};

