const LessonEngine = ({ dayId, onComplete, onExit }: { dayId: number, onComplete: () => void, onExit: () => void }) => {
    const lesson = WEEK_1_CONTENT.find(d => d.day === dayId);
    const [stepIndex, setStepIndex] = useState(0);
    const [selectedOption, setSelectedOption] = useState<number | null>(null);
    const [showResult, setShowResult] = useState(false); // For quiz feedback
    const [isCorrect, setIsCorrect] = useState(false);
    const [showSensei, setShowSensei] = useState(false);

    if (!lesson) return <div>加载中...</div>;

    const currentStep = lesson.steps[stepIndex];
    const progress = stepIndex / lesson.steps.length;

    const handleContinue = () => {
        if (currentStep.type === 'quiz' && !showResult) {
            // Check answer
            if (selectedOption === null) return;
            const correct = selectedOption === currentStep.correct;
            setIsCorrect(correct);
            setShowResult(true);

            // Play sound effect (optional/simulated)
            if (!correct) return; // Don't advance if wrong? Or allow retry. 
            // Duolingo style: usually forces you to get it right or loops back.
            // For simplicity here, we allow proceeding but show red.
        } else {
            // Next step
            if (stepIndex < lesson.steps.length - 1) {
                setStepIndex(prev => prev + 1);
                setSelectedOption(null);
                setShowResult(false);
            } else {
                onComplete();
            }
        }
    };

    return (
        <div className="fixed inset-0 bg-white z-50 flex flex-col">
            {/* Header */}
            <div className="p-4 flex items-center gap-4">
                <button onClick={onExit} className="text-gray-400 hover:text-gray-600">
                    <i className="fa-solid fa-xmark text-2xl"></i>
                </button>
                <ProgressBar current={stepIndex + 1} total={lesson.steps.length} />
            </div>

            {/* Content Area */}
            <div className="flex-1 flex flex-col items-center justify-center p-6 max-w-2xl mx-auto w-full overflow-y-auto">

                {currentStep.type === 'theory' && (
                    <div className="text-center animate-bounce-slight" style={{animation: 'none'}}>
                        <h2 className="text-2xl font-bold mb-6 text-gray-800">新概念</h2>
                        <div className="text-lg text-gray-600 leading-relaxed mb-8 border-l-4 border-orange-400 pl-4 text-left">
                            {currentStep.content}
                        </div>
                        <div className="text-6xl text-orange-400 mb-8">
                            <i className="fa-solid fa-lightbulb"></i>
                        </div>
                    </div>
                )}

                {currentStep.type === 'quiz' && (
                    <div className="w-full">
                        <h2 className="text-2xl font-bold mb-8 text-gray-800">{currentStep.question}</h2>
                        <div className="space-y-4">
                            {currentStep.options?.map((opt, idx) => (
                                <button
                                    key={idx}
                                    onClick={() => !showResult && setSelectedOption(idx)}
                                    className={`
                                        w-full p-4 rounded-xl border-2 text-left text-lg font-medium transition-all
                                        ${showResult && idx === currentStep.correct ? 'bg-green-100 border-green-500 text-green-700' : ''}
                                        ${showResult && idx === selectedOption && idx !== currentStep.correct ? 'bg-red-100 border-red-500 text-red-700' : ''}
                                        ${!showResult && selectedOption === idx ? 'bg-blue-100 border-blue-500 text-blue-700' : 'bg-white border-gray-200 hover:bg-gray-50'}
                                    `}
                                >
                                    {opt}
                                </button>
                            ))}
                        </div>
                    </div>
                )}

            </div>

            {/* AI Sensei Button */}
            <div className="absolute top-20 right-4">
                <button 
                  onClick={() => setShowSensei(true)}
                  className="bg-indigo-100 text-indigo-600 w-10 h-10 rounded-full flex items-center justify-center hover:bg-indigo-200 shadow-sm border border-indigo-200"
                  title="Ask AI Sensei"
                >
                    <i className="fa-solid fa-robot"></i>
                </button>
            </div>
            {showSensei && <ChatSensei context={currentStep.type === 'theory' ? currentStep.content : currentStep.question || ""} onClose={() => setShowSensei(false)} />}

            {/* Footer */}
            <div className={`p-4 border-t ${showResult ? (isCorrect ? 'bg-green-100 border-green-300' : 'bg-red-100 border-red-300') : 'bg-white'}`}>
                <div className="max-w-2xl mx-auto flex justify-between items-center">
                    {showResult && (
                        <div className="flex gap-3 items-center">
                            <div className={`w-10 h-10 rounded-full flex items-center justify-center text-white ${isCorrect ? 'bg-green-500' : 'bg-red-500'}`}>
                                <i className={`fa-solid ${isCorrect ? 'fa-check' : 'fa-xmark'}`}></i>
                            </div>
                            <div className={`font-bold ${isCorrect ? 'text-green-700' : 'text-red-700'}`}>
                                {isCorrect ? "正确！" : "不太对..."}
                            </div>
                        </div>
                    )}
                    <div className="flex-1"></div>
                    <button 
                        onClick={handleContinue}
                        disabled={currentStep.type === 'quiz' && !showResult && selectedOption === null}
                        className={`
                            px-8 py-3 rounded-xl font-bold text-white uppercase tracking-wide shadow-lg btn-press
                            ${showResult && !isCorrect ? 'bg-red-500 hover:bg-red-600' : 'bg-green-500 hover:bg-green-600'}
                            disabled:opacity-50 disabled:cursor-not-allowed
                        `}
                    >
                        {showResult && !isCorrect ? "再试一次" : "继续"}
                    </button>
                </div>
            </div>
        </div>
    );
};

