const App = () => {
    // State
    const [view, setView] = useState<'map' | 'week' | 'lesson'>('map');
    const [activeWeek, setActiveWeek] = useState(1);
    const [activeDay, setActiveDay] = useState(1);

    // Progress persistence could be added with localStorage
    const [completedDays, setCompletedDays] = useState(0); // 0 to 7
    const [collectedShards, setCollectedShards] = useState(0);
    const [collectedBalls, setCollectedBalls] = useState(0);

    const [rewardQueue, setRewardQueue] = useState<('shard' | 'ball')[]>([]);

    const handleSelectWeek = (id: number) => {
        setActiveWeek(id);
        setView('week');
    };

    const handlePlayDay = (day: number) => {
        setActiveDay(day);
        setView('lesson');
    };

    const handleLessonComplete = () => {
        // Logic for completion
        const isNewCompletion = activeDay > completedDays;

        if (isNewCompletion) {
            setCompletedDays(prev => prev + 1);
            setCollectedShards(prev => prev + 1);
            setRewardQueue(prev => [...prev, 'shard']);

            // Check for week completion (7 days)
            if (activeDay === 7) {
                // Short delay for the second reward
                setTimeout(() => {
                    setCollectedBalls(prev => prev + 1);
                    setCollectedShards(0); // Reset shards? Or keep them. Usually convert.
                    setRewardQueue(prev => [...prev, 'ball']);
                }, 500);
            }
        }

        setView('week');
    };

    const handleCloseReward = () => {
        setRewardQueue(prev => prev.slice(1));
    };

    return (
        <div className="mx-auto max-w-md bg-gray-50 min-h-screen shadow-2xl overflow-hidden relative">
            {view === 'map' && (
                <WorldMap 
                    unlockedWeek={1 + Math.floor(collectedBalls)} // Simple logic: 1 ball unlocks week 2
                    collectedBalls={collectedBalls} 
                    onSelectWeek={handleSelectWeek} 
                />
            )}

            {view === 'week' && (
                <WeekLevelView 
                    weekId={activeWeek} 
                    completedDays={completedDays} // In a real app, this would be per-week
                    onPlayDay={handlePlayDay}
                    onBack={() => setView('map')}
                />
            )}

            {view === 'lesson' && (
                <LessonEngine 
                    dayId={activeDay}
                    onComplete={handleLessonComplete}
                    onExit={() => setView('week')}
                />
            )}

            {/* Bottom Nav (only on Map) */}
            {view === 'map' && (
                <div className="fixed bottom-0 left-0 right-0 bg-white border-t p-2 flex justify-around max-w-md mx-auto">
                    <button className="flex flex-col items-center p-2 text-orange-500">
                        <i className="fa-solid fa-map text-xl"></i>
                        <span className="text-xs font-bold">学习</span>
                    </button>
                    <button className="flex flex-col items-center p-2 text-gray-400 hover:text-gray-600">
                         <i className="fa-solid fa-scroll text-xl"></i>
                        <span className="text-xs font-bold">任务</span>
                    </button>
                    <button className="flex flex-col items-center p-2 text-gray-400 hover:text-gray-600">
                        <i className="fa-solid fa-user-ninja text-xl"></i>
                        <span className="text-xs font-bold">我的</span>
                    </button>
                </div>
            )}

            {/* Rewards Overlay */}
            {rewardQueue.length > 0 && (
                <RewardModal type={rewardQueue[0]} onClose={handleCloseReward} />
            )}
        </div>
    );
};

