// --- Question Components ---
const MatchGame = ({ step, onCorrect }: { step: LessonStep, onCorrect: () => void }) => {
    const [leftSelected, setLeftSelected] = useState<string | null>(null);
    const [matched, setMatched] = useState<Set<string>>(new Set());
    const [shuffledRight, setShuffledRight] = useState<{id: string, text: string}[]>([]);
    useEffect(() => {
        if (step.pairs) {
            const items = step.pairs.map(p => ({ id: p.left, text: p.right }));
            setShuffledRight([...items].sort(() => Math.random() - 0.5));
        }
    }, [step]);
    const handleRightClick = (id: string) => {
        if (matched.has(id)) return;
        if (leftSelected === id) {
            SoundSynth.play('match');
            const nm = new Set(matched); nm.add(id); setMatched(nm); setLeftSelected(null);
            if (nm.size === step.pairs?.length) setTimeout(onCorrect, 500);
        } else { SoundSynth.play('wrong'); setLeftSelected(null); }
    };
    return (
        <div className="w-full flex gap-4">
            <div className="w-1/2 flex flex-col gap-3">
                {step.pairs?.map(p => (
                    <button key={p.left} onClick={() => { setLeftSelected(p.left); SoundSynth.play('pop'); }} disabled={matched.has(p.left)} className={`p-3 rounded-lg border-2 font-bold ${matched.has(p.left) ? 'opacity-30' : leftSelected === p.left ? 'border-indigo-500 bg-indigo-50' : 'bg-white'}`}>{p.left}</button>
                ))}
            </div>
            <div className="w-1/2 flex flex-col gap-3">
                {shuffledRight.map(p => (
                    <button key={p.id} onClick={() => handleRightClick(p.id)} disabled={matched.has(p.id)} className={`p-3 rounded-lg border-2 ${matched.has(p.id) ? 'opacity-30 bg-green-50 border-green-500' : 'bg-white'}`}>{p.text}</button>
                ))}
            </div>
        </div>
    );
};

