    const lesson = WEEK_1_CONTENT.find(d => d.day === dayId);
    const [steps, setSteps] = useState<LessonStep[]>([]);
    const [idx, setIdx] = useState(0);
    const [showResult, setShowResult] = useState(false);
    const [isCorrect, setIsCorrect] = useState(false);
    const [selectedO, setSelectedO] = useState<number | null>(null);
    const [showS, setShowS] = useState(false);

    useEffect(() => { if (lesson) setSteps(lesson.steps); }, [lesson]);

    const handleContinue = () => {
        if (idx < steps.length - 1) {
            setIdx(idx + 1);
            setShowResult(false);
            setSelectedO(null);
        } else {
            SoundSynth.play('complete');
            onComplete();
        }
    };

    const handleBack = () => {
        if (idx > 0) {
            setIdx(idx - 1);
            setShowResult(false);
            setSelectedO(null);
