                {step.parts?.map((part, i) => part === "___" ? (
                    <span key={i} className={`border-b-4 px-2 font-bold min-w-[80px] text-center transition-colors ${isSubmitted ? (selected === step.correct ? 'border-green-500 text-green-600' : 'border-red-500 text-red-600') : 'border-gray-300 text-indigo-600'}`}>{selected || "____"}</span>
