import React, { useState, useEffect, useRef } from 'react';
import { createRoot } from 'react-dom/client';
import { GoogleGenAI } from "@google/genai";
import { WEEKS, ALL_CURRICULUM } from './curriculum';
import { LessonStep, DayContent } from './types';

// --- Audio System (Synthesizer) ---
const SoundSynth = {
  ctx: null as AudioContext | null,
  init: () => {
    if (!SoundSynth.ctx) {
      SoundSynth.ctx = new (window.AudioContext || (window as any).webkitAudioContext)();
    }
    if (SoundSynth.ctx.state === 'suspended') {
      SoundSynth.ctx.resume();
    }
  },
  playTone: (freq: number, type: 'sine' | 'square' | 'triangle' | 'sawtooth', duration: number, startTime = 0) => {
    if (!SoundSynth.ctx) SoundSynth.init();
    const ctx = SoundSynth.ctx!;
    const osc = ctx.createOscillator();
    const gain = ctx.createGain();
    osc.type = type;
    osc.frequency.setValueAtTime(freq, ctx.currentTime + startTime);
    gain.gain.setValueAtTime(0.1, ctx.currentTime + startTime);
    gain.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + startTime + duration);
    osc.connect(gain);
    gain.connect(ctx.destination);
    osc.start(ctx.currentTime + startTime);
    osc.stop(ctx.currentTime + startTime + duration);
  },
  play: (effect: 'pop' | 'correct' | 'wrong' | 'success' | 'complete' | 'click' | 'match') => {
    SoundSynth.init();
    switch (effect) {
      case 'pop': SoundSynth.playTone(600 + Math.random() * 200, 'sine', 0.1); break;
      case 'click': SoundSynth.playTone(400, 'sine', 0.05); break;
      case 'match': SoundSynth.playTone(880, 'sine', 0.1); break;
      case 'correct':
        SoundSynth.playTone(523.25, 'sine', 0.1, 0);
        SoundSynth.playTone(659.25, 'sine', 0.1, 0.1);
        SoundSynth.playTone(783.99, 'sine', 0.2, 0.2);
        break;
      case 'wrong': SoundSynth.playTone(150, 'sawtooth', 0.3); SoundSynth.playTone(100, 'sawtooth', 0.3, 0.1); break;
      case 'success': [523.25, 659.25, 783.99, 1046.50].forEach((f, i) => SoundSynth.playTone(f, 'triangle', 0.3, i * 0.1)); break;
      case 'complete': SoundSynth.playTone(440, 'sine', 0.1); break;
    }
  }
};

// --- Confetti Component ---
const Confetti = () => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;
    canvas.width = window.innerWidth;
    canvas.height = window.innerHeight;
    const particles: any[] = [];
    const colors = ['#EF4444', '#F59E0B', '#10B981', '#3B82F6', '#8B5CF6'];
    for (let i = 0; i < 100; i++) {
      particles.push({
        x: window.innerWidth / 2, y: window.innerHeight / 2,
        color: colors[Math.floor(Math.random() * colors.length)],
        v: { x: (Math.random() - 0.5) * 15, y: (Math.random() - 0.5) * 15 - 5 },
        spin: Math.random() * 0.2 - 0.1
      });
    }
    let animationId: number;
    const render = () => {
      ctx.clearRect(0, 0, canvas.width, canvas.height);
      particles.forEach((p, i) => {
        p.x += p.v.x; p.y += p.v.y; p.v.y += 0.2; p.v.x *= 0.96;
        ctx.save(); ctx.translate(p.x, p.y); ctx.rotate(p.spin * i);
        ctx.fillStyle = p.color; ctx.fillRect(-5, -5, 10, 10); ctx.restore();
      });
      if (particles.some(p => p.y < canvas.height)) animationId = requestAnimationFrame(render);
    };
    render();
    return () => cancelAnimationFrame(animationId);
  }, []);
  return <canvas ref={canvasRef} className="fixed inset-0 pointer-events-none z-[70]" />;
};

// --- Sub-Components ---
const ProgressBar = ({ current, total }: { current: number, total: number }) => (
  <div className="w-full bg-gray-200 rounded-full h-3 mb-6 relative overflow-hidden">
    <div className="absolute inset-0 bg-gray-200"></div>
    <div className="bg-green-500 h-3 rounded-full transition-all duration-500 relative z-10" style={{ width: `${(current / total) * 100}%` }}>
      <div className="absolute right-0 top-0 bottom-0 w-2 bg-white/30 animate-pulse"></div>
