                            onClick={() => { if (isUnlocked) { SoundSynth.play('pop'); onSelectWeek(week.id); } }}
                        />
                    </div>
                );
            })}
        </div>
      </div>

      {/* Bottom Decoration */}
      <div className="absolute bottom-0 w-full h-10 flex items-center justify-around pointer-events-none opacity-20">
          {[...Array(8)].map((_, i) => <i key={i} className="fa-solid fa-leaf text-green-900 text-xl"></i>)}
      </div>
    </div>
);

const WeekLevelView = ({ weekId, completedDays, onPlayDay, onBack }: { weekId: number, completedDays: number, onPlayDay: (day: number) => void, onBack: () => void }) => {
    const week = WEEKS.find(w => w.id === weekId);
    const currentWeekContent = ALL_CURRICULUM[weekId] || [];
    return (
        <div className="min-h-screen bg-[#3f64e7] relative overflow-hidden flex flex-col">
            <div className="p-4 text-white z-10 flex items-center gap-4">
                <button onClick={() => { SoundSynth.play('pop'); onBack(); }} className="hover:bg-white/20 p-2 rounded-full transition"><i className="fa-solid fa-arrow-left"></i></button>
                <h2 className="text-xl font-bold">{week?.title}</h2>
            </div>
            <div className="flex-1 flex flex-col items-center justify-center relative pb-20">
                {currentWeekContent.map((day, idx) => {
                    const isUnlocked = idx <= completedDays;
                    const isCompleted = idx < completedDays;
                    const isCurrent = idx === completedDays;
                    const offsetClass = idx % 2 === 0 ? '-translate-x-12' : 'translate-x-12';
                    return (
                        <div key={day.day} className={`relative my-4 transition-all duration-500 ${offsetClass} animate-pop`} style={{animationDelay: `${idx * 0.1}s`}}>
                            <button onClick={() => { if (isUnlocked) { SoundSynth.play('pop'); onPlayDay(day.day); } }} disabled={!isUnlocked} className={`w-20 h-20 rounded-full border-b-8 flex items-center justify-center text-2xl shadow-xl transition-transform active:translate-y-1 active:border-b-0 ${isCompleted ? 'bg-yellow-400 border-yellow-600 text-yellow-900' : ''} ${isCurrent ? 'bg-orange-500 border-orange-700 text-white animate-bounce-slight' : ''} ${!isUnlocked && !isCompleted ? 'bg-gray-400 border-gray-600 text-gray-200 cursor-not-allowed' : ''}`}>
                                {isCompleted ? <i className="fa-solid fa-check"></i> : !isUnlocked ? <i className="fa-solid fa-lock"></i> : day.isBoss ? <i className="fa-solid fa-skull"></i> : <i className="fa-solid fa-star"></i>}
                            </button>
                            <div className="absolute top-full mt-2 left-1/2 -translate-x-1/2 bg-black/40 text-white text-xs px-2 py-1 rounded whitespace-nowrap">第 {day.day} 天</div>
                        </div>
                    );
                })}
            </div>
        </div>
    );
};

const LessonEngine = ({ weekId, dayId, onComplete, onExit }: { weekId: number, dayId: number, onComplete: () => void, onExit: () => void }) => {
    const lessonData = ALL_CURRICULUM[weekId]?.find(d => d.day === dayId);
    const [steps, setSteps] = useState<LessonStep[]>([]);
    const [stepIndex, setStepIndex] = useState(0);
    const [mistakes, setMistakes] = useState<LessonStep[]>([]);
    const [isReviewMode, setIsReviewMode] = useState(false);
    const [selectedOption, setSelectedOption] = useState<number | null>(null);
    const [showResult, setShowResult] = useState(false);
    const [isCorrect, setIsCorrect] = useState(false);
    const [shake, setShake] = useState(false);
    const [showSensei, setShowSensei] = useState(false);

    useEffect(() => { 
        if (lessonData) {
            // Randomize between Bank A and Bank B for each step if they exist
            if (lessonData.stepsA && lessonData.stepsB && lessonData.stepsA.length === lessonData.stepsB.length) {
                const combined = lessonData.stepsA.map((stepA, i) => 
                    Math.random() > 0.5 ? stepA : (lessonData.stepsB![i])
                );
                setSteps(combined);
            } else {
                setSteps(lessonData.steps || []);
            }
        } 
    }, [lessonData]);

    useEffect(() => { setSelectedOption(null); setShowResult(false); setIsCorrect(false); setShake(false); }, [stepIndex, isReviewMode]);

    if (!steps.length) return <div>加载中...</div>;
    const currentStep = steps[stepIndex];

    const handleQuizCheck = () => {
        if (!showResult && selectedOption !== null) {
            const correct = selectedOption === currentStep.correct;
            setIsCorrect(correct); setShowResult(true);
            if (correct) SoundSynth.play('correct');
            else { SoundSynth.play('wrong'); setShake(true); setTimeout(() => setShake(false), 500); if (!isReviewMode) setMistakes(prev => [...prev, currentStep]); }
        }
    };
    const handleMatchComplete = () => { setIsCorrect(true); setShowResult(true); SoundSynth.play('correct'); };
    const handleFillResult = (correct: boolean) => {
        setIsCorrect(correct); setShowResult(true);
        if (correct) SoundSynth.play('correct');
        else { SoundSynth.play('wrong'); if (!isReviewMode) setMistakes(prev => [...prev, currentStep]); }
    };
    const handleContinue = () => {
        SoundSynth.play('pop');
        if (stepIndex < steps.length - 1) setStepIndex(prev => prev + 1);
        else {
            if (!isReviewMode && mistakes.length > 0) { setSteps(mistakes); setStepIndex(0); setMistakes([]); setIsReviewMode(true); }
            else if (isReviewMode && mistakes.length > 0) { setSteps(mistakes); setStepIndex(0); setMistakes([]); }
            else { SoundSynth.play('complete'); onComplete(); }
        }
    };
    const handleBack = () => { if (stepIndex > 0) { SoundSynth.play('click'); setStepIndex(prev => prev - 1); } };

    return (
        <div className="fixed inset-0 bg-white z-50 flex flex-col">
            <div className={`p-4 flex items-center gap-4 ${isReviewMode ? 'bg-orange-100' : ''}`}>
                <div className="flex items-center gap-2">
                    <button onClick={() => { SoundSynth.play('click'); onExit(); }} className="text-gray-400 hover:text-gray-600"><i className="fa-solid fa-xmark text-2xl"></i></button>
                    <button onClick={handleBack} disabled={stepIndex === 0} className={`p-2 rounded-full transition ${stepIndex === 0 ? 'text-gray-200 cursor-not-allowed' : 'text-gray-400 hover:bg-gray-100 hover:text-gray-600'}`} title="回退"><i className="fa-solid fa-arrow-left text-xl"></i></button>
                </div>
                <div className="flex-1">{isReviewMode ? <div className="text-center font-bold text-orange-600 animate-pulse"><i className="fa-solid fa-rotate-left"></i> 错题复习中...</div> : <ProgressBar current={stepIndex + 1} total={steps.length} />}</div>
            </div>
            <div className="flex-1 flex flex-col items-center justify-center p-6 max-w-2xl mx-auto w-full overflow-y-auto">
                {(currentStep.type === 'theory' || currentStep.type === 'boss') && (
                    <div className="text-center animate-slide-up">
                        <h2 className="text-2xl font-bold mb-6 text-gray-800">{currentStep.isBoss ? "终极考验" : "任务简报"}</h2>
                        <div className={`text-lg text-gray-600 leading-relaxed mb-8 border-l-4 pl-4 text-left ${currentStep.isBoss ? 'border-red-600 bg-red-50 p-4' : 'border-orange-400'}`}>{currentStep.content}</div>
                        <div className={`text-6xl mb-8 ${currentStep.isBoss ? 'text-red-600' : 'text-orange-400'} animate-bounce-slight`}><i className={`fa-solid ${currentStep.isBoss ? 'fa-dragon' : 'fa-lightbulb'}`}></i></div>
                    </div>
                )}
                {currentStep.type === 'quiz' && <div className="w-full animate-slide-up"><h2 className="text-2xl font-bold mb-8 text-gray-800">{currentStep.question}</h2><div className={`space-y-4 ${shake ? 'animate-shake' : ''}`}>{currentStep.options?.map((opt, idx) => (<button key={idx} onClick={() => { if (!showResult) { SoundSynth.play('pop'); setSelectedOption(idx); } }} className={`w-full p-4 rounded-xl border-2 text-left text-lg font-medium transition-all active:scale-95 ${showResult && idx === currentStep.correct ? 'bg-green-100 border-green-500 text-green-700' : ''} ${showResult && idx === selectedOption && idx !== currentStep.correct ? 'bg-red-100 border-red-500 text-red-700' : ''} ${!showResult && selectedOption === idx ? 'bg-blue-100 border-blue-500 text-blue-700' : 'bg-white border-gray-200 hover:bg-gray-50'}`}>{opt}</button>))}</div></div>}
                {currentStep.type === 'match' && <div className="w-full"><h2 className="text-2xl font-bold mb-6 text-gray-800">{currentStep.question}</h2><MatchGame step={currentStep} onCorrect={handleMatchComplete} /></div>}
                {currentStep.type === 'fill' && <div className="w-full"><h2 className="text-2xl font-bold mb-6 text-gray-800">{currentStep.question}</h2><FillBlank step={currentStep} onResult={handleFillResult} /></div>}
            </div>
            <div className="absolute top-20 right-4"><button onClick={() => { SoundSynth.play('pop'); setShowSensei(true); }} className="bg-indigo-100 text-indigo-600 w-10 h-10 rounded-full flex items-center justify-center hover:bg-indigo-200 shadow-sm border border-indigo-200 transition-transform hover:scale-110 active:scale-90" title="Ask AI Sensei"><i className="fa-solid fa-robot"></i></button></div>
            {showSensei && <ChatSensei context={currentStep.type === 'theory' || currentStep.type === 'boss' ? (currentStep.content || "") : (currentStep.question || "")} onClose={() => setShowSensei(false)} />}
            <div className={`p-4 border-t ${showResult ? (isCorrect ? 'bg-green-100 border-green-300' : 'bg-red-100 border-red-300') : 'bg-white'}`}>
                <div className="max-w-2xl mx-auto flex justify-between items-center">
                    {showResult && <div className="flex gap-3 items-center animate-pop"><div className={`w-10 h-10 rounded-full flex items-center justify-center text-white ${isCorrect ? 'bg-green-500' : 'bg-red-500'}`}><i className={`fa-solid ${isCorrect ? 'fa-check' : 'fa-xmark'}`}></i></div><div className={`font-bold ${isCorrect ? 'text-green-700' : 'text-red-700'}`}>{isCorrect ? "正确！" : "再试试？"}</div></div>}
                    <div className="flex-1"></div>
                    {currentStep.type === 'quiz' && !showResult ? <button onClick={handleQuizCheck} disabled={selectedOption === null} className="px-8 py-3 rounded-xl font-bold text-white uppercase tracking-wide shadow-lg btn-press bg-green-500 hover:bg-green-600 disabled:opacity-50">检查</button> : (currentStep.type === 'theory' || currentStep.type === 'boss' || showResult) ? <button onClick={handleContinue} className={`px-8 py-3 rounded-xl font-bold text-white uppercase tracking-wide shadow-lg btn-press ${showResult && !isCorrect ? 'bg-red-500 hover:bg-red-600' : 'bg-green-500 hover:bg-green-600'}`}>继续</button> : null}
                </div>
            </div>
        </div>
    );
};

const App = () => {
  const [view, setView] = useState<'world' | 'week' | 'lesson'>('world');
  const [selectedWeekId, setSelectedWeekId] = useState<number | null>(null);
  const [selectedDayId, setSelectedDayId] = useState<number | null>(null);

  const [unlockedWeek, setUnlockedWeek] = useState(1);
  const [collectedBalls, setCollectedBalls] = useState(0);
  const [completedDays, setCompletedDays] = useState(0);
  const [showConfetti, setShowConfetti] = useState(false);

  const handleSelectWeek = (id: number) => { setSelectedWeekId(id); setView('week'); };
  const handleBackToWorld = () => { setView('world'); setSelectedWeekId(null); };
  const handlePlayDay = (dayId: number) => { setSelectedDayId(dayId); setView('lesson'); };
  const handleLessonExit = () => { setView('week'); setSelectedDayId(null); };

  const handleUnlockAll = () => {
    setUnlockedWeek(7);
    setCollectedBalls(6);
    setCompletedDays(7);
    setShowConfetti(true);
    setTimeout(() => setShowConfetti(false), 3000);
  };

  const handleLessonComplete = () => {
    if (selectedWeekId === 1 && selectedDayId === completedDays + 1) {
        const newCompleted = completedDays + 1;
        setCompletedDays(newCompleted);
        const currentWeekDays = ALL_CURRICULUM[1]?.length || 0;
        if (newCompleted === currentWeekDays) {
            setCollectedBalls(prev => Math.min(prev + 1, 7));
            if (unlockedWeek < WEEKS.length) setUnlockedWeek(prev => prev + 1);
            setShowConfetti(true); setTimeout(() => setShowConfetti(false), 5000);
        }
    }
    setView('week'); setSelectedDayId(null);
  };

  return (
    <div className="font-sans bg-gray-50 min-h-screen select-none text-gray-900">
        {showConfetti && <Confetti />}
        {view === 'world' && <WorldMap unlockedWeek={unlockedWeek} onSelectWeek={handleSelectWeek} collectedBalls={collectedBalls} onUnlockAll={handleUnlockAll} />}
        {view === 'week' && selectedWeekId && <WeekLevelView weekId={selectedWeekId} completedDays={completedDays} onPlayDay={handlePlayDay} onBack={handleBackToWorld} />}
        {view === 'lesson' && selectedWeekId && selectedDayId && <LessonEngine weekId={selectedWeekId} dayId={selectedDayId} onComplete={handleLessonComplete} onExit={handleLessonExit} />}
    </div>
  );
};

const root = createRoot(document.getElementById('root')!);
root.render(<App />);

import React, { useState, useEffect, useRef } from 'react';
import { createRoot } from 'react-dom/client';
import { GoogleGenAI } from "@google/genai";
import { WEEKS, ALL_CURRICULUM } from './curriculum';
import { LessonStep, DayContent } from './types';

// --- Audio System (Synthesizer) ---
const SoundSynth = {
  ctx: null as AudioContext | null,
  init: () => {
    if (!SoundSynth.ctx) {
      SoundSynth.ctx = new (window.AudioContext || (window as any).webkitAudioContext)();
    }
    if (SoundSynth.ctx.state === 'suspended') {
      SoundSynth.ctx.resume();
    }
  },
  playTone: (freq: number, type: 'sine' | 'square' | 'triangle' | 'sawtooth', duration: number, startTime = 0) => {
    if (!SoundSynth.ctx) SoundSynth.init();
    const ctx = SoundSynth.ctx!;
    const osc = ctx.createOscillator();
    const gain = ctx.createGain();
    osc.type = type;
    osc.frequency.setValueAtTime(freq, ctx.currentTime + startTime);
    gain.gain.setValueAtTime(0.1, ctx.currentTime + startTime);
    gain.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + startTime + duration);
    osc.connect(gain);
    gain.connect(ctx.destination);
    osc.start(ctx.currentTime + startTime);
    osc.stop(ctx.currentTime + startTime + duration);
  },
  play: (effect: 'pop' | 'correct' | 'wrong' | 'success' | 'complete' | 'click' | 'match') => {
    SoundSynth.init();
    switch (effect) {
      case 'pop': SoundSynth.playTone(600 + Math.random() * 200, 'sine', 0.1); break;
      case 'click': SoundSynth.playTone(400, 'sine', 0.05); break;
      case 'match': SoundSynth.playTone(880, 'sine', 0.1); break;
      case 'correct':
        SoundSynth.playTone(523.25, 'sine', 0.1, 0);
        SoundSynth.playTone(659.25, 'sine', 0.1, 0.1);
        SoundSynth.playTone(783.99, 'sine', 0.2, 0.2);
        break;
      case 'wrong': SoundSynth.playTone(150, 'sawtooth', 0.3); SoundSynth.playTone(100, 'sawtooth', 0.3, 0.1); break;
      case 'success': [523.25, 659.25, 783.99, 1046.50].forEach((f, i) => SoundSynth.playTone(f, 'triangle', 0.3, i * 0.1)); break;
      case 'complete': SoundSynth.playTone(440, 'sine', 0.1); break;
    }
  }
};

// --- Confetti Component ---
const Confetti = () => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;
    canvas.width = window.innerWidth;
    canvas.height = window.innerHeight;
    const particles: any[] = [];
    const colors = ['#FCD34D', '#FBBF24', '#10B981', '#34D399', '#FFF7ED'];
    for (let i = 0; i < 100; i++) {
      particles.push({
        x: window.innerWidth / 2, y: window.innerHeight / 2,
        color: colors[Math.floor(Math.random() * colors.length)],
        v: { x: (Math.random() - 0.5) * 15, y: (Math.random() - 0.5) * 15 - 5 },
        spin: Math.random() * 0.2 - 0.1
      });
    }
    let animationId: number;
    const render = () => {
      ctx.clearRect(0, 0, canvas.width, canvas.height);
      particles.forEach((p, i) => {
        p.x += p.v.x; p.y += p.v.y; p.v.y += 0.2; p.v.x *= 0.96;
        ctx.save(); ctx.translate(p.x, p.y); ctx.rotate(p.spin * i);
        ctx.fillStyle = p.color; ctx.fillRect(-5, -5, 10, 10); ctx.restore();
      });
      if (particles.some(p => p.y < canvas.height)) animationId = requestAnimationFrame(render);
    };
    render();
    return () => cancelAnimationFrame(animationId);
  }, []);
  return <canvas ref={canvasRef} className="fixed inset-0 pointer-events-none z-[70]" />;
};

// --- Sub-Components ---
const ProgressBar = ({ current, total }: { current: number, total: number }) => (
  <div className="w-full bg-gray-100 rounded-full h-3 mb-6 relative overflow-hidden border border-green-100">
    <div className="absolute inset-0 bg-gray-100"></div>
    <div className="bg-yellow-500 h-3 rounded-full transition-all duration-500 relative z-10 shadow-[0_0_8px_rgba(245,158,11,0.5)]" style={{ width: `${(current / total) * 100}%` }}>
      <div className="absolute right-0 top-0 bottom-0 w-4 bg-white/40 skew-x-[-20deg]"></div>
    </div>
  </div>
);

const ChatSensei = ({ context, onClose }: { context: string, onClose: () => void }) => {
  const [messages, setMessages] = useState<{role: 'user'|'model', text: string}[]>([
    { role: 'model', text: "我是你的AI导师。关于这节课，尽管问我！" }
  ]);
  const [input, setInput] = useState("");
  const [loading, setLoading] = useState(false);
  const messagesEndRef = useRef<HTMLDivElement>(null);
  const scrollToBottom = () => messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  useEffect(scrollToBottom, [messages]);
  const handleSend = async () => {
    if (!input.trim() || loading) return;
    SoundSynth.play('pop');
    setMessages(prev => [...prev, { role: 'user', text: input }]);
    setInput("");
    setLoading(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: [{ role: "user", parts: [{ text: `Context: 你是一个面向初学者的AI教学App中友好、睿智且简洁的AI导师。当前课程内容是："${context}"。用户问："${input}"。请用中文简短且鼓励性地回答。` }] }]
      });
      SoundSynth.play('pop');
      setMessages(prev => [...prev, { role: 'model', text: response.text }]);
    } catch (e) {
      setMessages(prev => [...prev, { role: 'model', text: "我与以太的连接微弱。请重试。" }]);
    } finally { setLoading(false); }
  };
  return (
    <div className="fixed inset-0 bg-black/50 z-50 flex items-end sm:items-center justify-center p-4 backdrop-blur-sm">
      <div className="bg-white w-full max-w-md h-[80vh] rounded-3xl flex flex-col shadow-2xl overflow-hidden animate-pop border-4 border-yellow-100">
        <div className="bg-gradient-to-r from-yellow-500 to-green-500 p-5 text-white flex justify-between items-center">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 bg-white/20 rounded-full flex items-center justify-center border border-white/30">
                <i className="fa-solid fa-robot text-xl"></i>
            </div>
            <span className="font-bold text-lg tracking-tight">AI 导师</span>
          </div>
          <button onClick={() => { SoundSynth.play('click'); onClose(); }} className="w-8 h-8 flex items-center justify-center bg-white/20 rounded-full hover:bg-white/40 transition-colors">
            <i className="fa-solid fa-xmark"></i>
          </button>
        </div>
        <div className="flex-1 overflow-y-auto p-4 space-y-4 bg-yellow-50/30">
          {messages.map((m, i) => (
            <div key={i} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'} animate-slide-up`}>
              <div className={`max-w-[85%] p-4 rounded-2xl shadow-sm ${m.role === 'user' ? 'bg-yellow-500 text-white rounded-tr-none' : 'bg-white border border-yellow-200 text-gray-800 rounded-tl-none'}`}>{m.text}</div>
            </div>
          ))}
          {loading && <div className="flex justify-start"><div className="bg-white border border-yellow-200 p-3 rounded-2xl rounded-tl-none text-yellow-600"><i className="fa-solid fa-circle-notch fa-spin mr-2"></i> 龙心检索中...</div></div>}
          <div ref={messagesEndRef} />
        </div>
        <div className="p-4 bg-white border-t border-yellow-100 flex gap-2">
          <input type="text" value={input} onChange={(e) => setInput(e.target.value)} onKeyDown={(e) => e.key === 'Enter' && handleSend()} placeholder="向龙魂祈求指引..." className="flex-1 bg-yellow-50 border-2 border-yellow-100 rounded-full px-5 py-3 focus:outline-none focus:ring-2 focus:ring-yellow-400 transition-all" />
          <button onClick={handleSend} disabled={loading} className="bg-yellow-500 text-white w-12 h-12 rounded-full flex items-center justify-center hover:bg-yellow-600 disabled:opacity-50 transition-transform active:scale-90 shadow-lg"><i className="fa-solid fa-paper-plane"></i></button>
        </div>
      </div>
    </div>
  );
};

// --- Question Components ---
const MatchGame = ({ step, onCorrect }: { step: LessonStep, onCorrect: () => void }) => {
    const [leftSelected, setLeftSelected] = useState<string | null>(null);
    const [matched, setMatched] = useState<Set<string>>(new Set());
    const [shuffledRight, setShuffledRight] = useState<{id: string, text: string}[]>([]);
    useEffect(() => {
        if (step.pairs) {
            const rightItems = step.pairs.map(p => ({ id: p.left, text: p.right }));
            setShuffledRight(rightItems.sort(() => Math.random() - 0.5));
        }
    }, [step]);
    const handleLeftClick = (id: string) => { if (matched.has(id)) return; SoundSynth.play('pop'); setLeftSelected(id); };
    const handleRightClick = (id: string) => {
        if (matched.has(id)) return;
        if (leftSelected === id) {
            SoundSynth.play('match');
            const newMatched = new Set(matched); newMatched.add(id); setMatched(newMatched); setLeftSelected(null);
            if (newMatched.size === step.pairs?.length) setTimeout(onCorrect, 500);
        } else { SoundSynth.play('wrong'); setLeftSelected(null); }
    };
    return (
        <div className="w-full flex gap-4 justify-between animate-slide-up">
            <div className="flex flex-col gap-3 w-1/2">{step.pairs?.map(pair => (
                <button key={pair.left} onClick={() => handleLeftClick(pair.left)} disabled={matched.has(pair.left)} className={`p-4 rounded-2xl border-2 text-sm sm:text-base font-bold transition-all shadow-sm ${matched.has(pair.left) ? 'bg-green-50 border-green-300 text-green-700 opacity-50' : leftSelected === pair.left ? 'bg-yellow-100 border-yellow-400 text-yellow-800 scale-105 shadow-md' : 'bg-white border-yellow-100 hover:border-yellow-200 text-gray-700'}`}>{pair.left}</button>
            ))}</div>
            <div className="flex flex-col gap-3 w-1/2">{shuffledRight.map(item => (
                <button key={item.id} onClick={() => handleRightClick(item.id)} disabled={matched.has(item.id)} className={`p-4 rounded-2xl border-2 text-sm sm:text-base transition-all shadow-sm ${matched.has(item.id) ? 'bg-green-50 border-green-300 text-green-700 opacity-50' : 'bg-white border-yellow-100 hover:border-yellow-200 text-gray-600'}`}>{item.text}</button>
            ))}</div>
        </div>
    );
};

const FillBlank = ({ step, onResult }: { step: LessonStep, onResult: (correct: boolean) => void }) => {
    const [selected, setSelected] = useState<string | null>(null);
    const [isSubmitted, setIsSubmitted] = useState(false);
    const check = () => { if (!selected) return; setIsSubmitted(true); onResult(selected === step.correct); };
    return (
        <div className="w-full animate-slide-up">
            <div className="bg-white p-8 rounded-3xl border-2 border-yellow-100 mb-8 flex flex-wrap gap-2 items-baseline text-xl leading-relaxed shadow-sm">
                {step.parts?.map((part, i) => part === "___" ? (
                    <span key={i} className={`border-b-4 px-3 font-bold min-w-[100px] text-center transition-colors ${isSubmitted ? (selected === step.correct ? 'border-green-500 text-green-600' : 'border-red-500 text-red-600') : 'border-yellow-400 text-yellow-600'}`}>{selected || "____"}</span>
                ) : <span key={i} className="text-gray-700">{part}</span>)}
            </div>
            <div className="grid grid-cols-2 gap-4">{step.options?.map(opt => (
                <button key={opt} onClick={() => { if(!isSubmitted) { SoundSynth.play('pop'); setSelected(opt); } }} className={`p-4 rounded-2xl border-b-4 font-bold text-lg transition-all active:translate-y-1 active:border-b-0 ${selected === opt ? 'bg-yellow-100 border-yellow-400 text-yellow-800' : 'bg-white border-yellow-100 text-gray-600 hover:bg-yellow-50'}`}>{opt}</button>
            ))}</div>
             {!isSubmitted && <button onClick={check} disabled={!selected} className="w-full mt-8 bg-yellow-500 text-white py-4 rounded-2xl font-bold uppercase tracking-widest shadow-lg hover:bg-yellow-600 disabled:opacity-50 transition-colors">验证真名</button>}
        </div>
    );
};

