        ${isUnlocked ? `bg-gradient-to-br from-yellow-300 via-yellow-400 to-lime-500 border-white text-white shadow-[0_10px_20px_rgba(163,230,53,0.3)]` : 'bg-white/40 border-green-100 text-green-200 grayscale'}`}>

