        {[...Array(30)].map((_, i) => (
          <div key={i} className="absolute text-yellow-900/5 text-3xl" 
               style={{ top: `${Math.random() * 100}%`, left: `${Math.random() * 100}%`, transform: `rotate(${Math.random() * 40 - 20}deg)` }}>
