        <div className="flex items-center gap-4">
            <div className="bg-white/95 backdrop-blur-md px-6 py-2 rounded-full shadow-xl border-2 border-yellow-300 flex items-center gap-3 transform hover:scale-105 transition-all">
                <i className="fa-solid fa-dragon text-2xl text-yellow-600"></i>
