const LessonEngine = ({ weekId, dayId, onComplete, onExit }: { weekId: number, dayId: number, onComplete: () => void, onExit: () => void }) => {
    const lessonData = ALL_CURRICULUM[weekId]?.find(d => d.day === dayId);
    const [steps, setSteps] = useState<LessonStep[]>([]);
    const [stepIndex, setStepIndex] = useState(0);
    const [mistakes, setMistakes] = useState<LessonStep[]>([]);
    const [isReviewMode, setIsReviewMode] = useState(false);
    const [selectedOption, setSelectedOption] = useState<number | null>(null);
    const [showResult, setShowResult] = useState(false);
    const [isCorrect, setIsCorrect] = useState(false);
    const [shake, setShake] = useState(false);
    const [showSensei, setShowSensei] = useState(false);

    useEffect(() => { 
        if (lessonData) {
            if (lessonData.stepsA && lessonData.stepsB && lessonData.stepsA.length === lessonData.stepsB.length) {
                const combined = lessonData.stepsA.map((stepA, i) => 
                    Math.random() > 0.5 ? stepA : (lessonData.stepsB![i])
                );
                setSteps(combined);
            } else {
                setSteps(lessonData.steps || []);
            }
        } 
    }, [lessonData]);

    useEffect(() => { setSelectedOption(null); setShowResult(false); setIsCorrect(false); setShake(false); }, [stepIndex, isReviewMode]);

    if (!steps.length) return <div className="h-screen flex items-center justify-center bg-yellow-50 text-yellow-800 font-bold">载入龙之智慧...</div>;
    const currentStep = steps[stepIndex];

    const handleQuizCheck = () => {
        if (!showResult && selectedOption !== null) {
            const correct = selectedOption === currentStep.correct;
            setIsCorrect(correct); setShowResult(true);
            if (correct) SoundSynth.play('correct');
            else { SoundSynth.play('wrong'); setShake(true); setTimeout(() => setShake(false), 500); if (!isReviewMode) setMistakes(prev => [...prev, currentStep]); }
        }
    };
    const handleMatchComplete = () => { setIsCorrect(true); setShowResult(true); SoundSynth.play('correct'); };
    const handleFillResult = (correct: boolean) => {
        setIsCorrect(correct); setShowResult(true);
        if (correct) SoundSynth.play('correct');
        else { SoundSynth.play('wrong'); if (!isReviewMode) setMistakes(prev => [...prev, currentStep]); }
    };
    const handleContinue = () => {
        SoundSynth.play('pop');
        if (stepIndex < steps.length - 1) setStepIndex(prev => prev + 1);
        else {
            if (!isReviewMode && mistakes.length > 0) { setSteps(mistakes); setStepIndex(0); setMistakes([]); setIsReviewMode(true); }
            else if (isReviewMode && mistakes.length > 0) { setSteps(mistakes); setStepIndex(0); setMistakes([]); }
            else { SoundSynth.play('complete'); onComplete(); }
        }
    };
    const handleBack = () => { if (stepIndex > 0) { SoundSynth.play('click'); setStepIndex(prev => prev - 1); } };

    return (
        <div className="fixed inset-0 bg-yellow-50 z-50 flex flex-col">
            {/* Engine Header */}
            <div className={`p-4 flex items-center gap-4 ${isReviewMode ? 'bg-orange-100 shadow-inner' : 'bg-white shadow-sm'}`}>
                <div className="flex items-center gap-2">
                    <button onClick={() => { SoundSynth.play('click'); onExit(); }} className="w-10 h-10 flex items-center justify-center text-gray-400 hover:bg-gray-100 rounded-full"><i className="fa-solid fa-xmark text-2xl"></i></button>
                    <button onClick={handleBack} disabled={stepIndex === 0} className={`w-10 h-10 flex items-center justify-center rounded-full transition ${stepIndex === 0 ? 'text-gray-200 cursor-not-allowed' : 'text-gray-400 hover:bg-gray-100'}`}><i className="fa-solid fa-arrow-left text-xl"></i></button>
                </div>
                <div className="flex-1">
                    {isReviewMode ? 
                        <div className="text-center font-black text-orange-600 flex items-center justify-center gap-2 italic uppercase tracking-tighter animate-pulse"><i className="fa-solid fa-fire"></i> 复仇环节：突破错误！</div> : 
                        <ProgressBar current={stepIndex + 1} total={steps.length} />
                    }
                </div>
                <div className="w-10 h-10"></div>
            </div>

            {/* Step Content */}
            <div className="flex-1 flex flex-col items-center justify-center p-6 max-w-2xl mx-auto w-full overflow-y-auto">
                {(currentStep.type === 'theory' || currentStep.type === 'boss') && (
                    <div className="text-center animate-slide-up w-full">
                        <div className={`inline-block px-4 py-1 rounded-full text-[10px] font-black uppercase tracking-widest mb-4 ${currentStep.isBoss ? 'bg-red-100 text-red-600' : 'bg-yellow-100 text-yellow-700'}`}>
                            {currentStep.isBoss ? "终极仪式" : "龙之秘籍"}
                        </div>
                        <div className={`bg-white p-8 rounded-3xl border-2 shadow-sm text-left relative overflow-hidden mb-10 ${currentStep.isBoss ? 'border-red-200 bg-red-50/30' : 'border-yellow-100'}`}>
                            {/* Decorative corner icon */}
                            <div className="absolute -top-10 -right-10 text-9xl text-yellow-100/50 -rotate-12"><i className={`fa-solid ${currentStep.isBoss ? 'fa-skull' : 'fa-scroll'}`}></i></div>
                            <div className="relative z-10 text-lg sm:text-xl text-gray-700 leading-relaxed font-medium">{currentStep.content}</div>
                        </div>
                        <div className={`text-7xl ${currentStep.isBoss ? 'text-red-600' : 'text-yellow-500'} animate-bounce-slight`}><i className={`fa-solid ${currentStep.isBoss ? 'fa-dragon' : 'fa-lightbulb'}`}></i></div>
                    </div>
                )}

                {currentStep.type === 'quiz' && (
                    <div className="w-full animate-slide-up">
                        <h2 className="text-2xl sm:text-3xl font-black mb-10 text-gray-800 leading-tight tracking-tight border-l-8 border-yellow-400 pl-4">{currentStep.question}</h2>
                        <div className={`space-y-4 ${shake ? 'animate-shake' : ''}`}>
                            {currentStep.options?.map((opt, idx) => (
                                <button 
                                    key={idx} 
                                    onClick={() => { if (!showResult) { SoundSynth.play('pop'); setSelectedOption(idx); } }} 
                                    className={`w-full p-5 rounded-2xl border-b-4 text-left text-lg font-bold transition-all active:scale-[0.98] ${showResult && idx === currentStep.correct ? 'bg-green-500 border-green-700 text-white shadow-lg' : showResult && idx === selectedOption && idx !== currentStep.correct ? 'bg-red-500 border-red-700 text-white shadow-lg' : !showResult && selectedOption === idx ? 'bg-yellow-100 border-yellow-400 text-yellow-800' : 'bg-white border-yellow-100 text-gray-600 hover:border-yellow-300 shadow-sm'}`}
                                >
                                    <span className="inline-block w-8 h-8 rounded-lg bg-black/5 mr-3 text-center leading-8 font-black uppercase">{String.fromCharCode(65 + idx)}</span>
                                    {opt}
                                </button>
                            ))}
                        </div>
                    </div>
                )}

                {currentStep.type === 'match' && (
                    <div className="w-full">
                        <h2 className="text-2xl sm:text-3xl font-black mb-8 text-gray-800 tracking-tight">{currentStep.question}</h2>
                        <MatchGame step={currentStep} onCorrect={handleMatchComplete} />
                    </div>
                )}

                {currentStep.type === 'fill' && (
                    <div className="w-full">
                        <h2 className="text-2xl sm:text-3xl font-black mb-8 text-gray-800 tracking-tight">{currentStep.question}</h2>
                        <FillBlank step={currentStep} onResult={handleFillResult} />
                    </div>
                )}
            </div>

            {/* AI Sensei Floating Button */}
            <div className="absolute top-24 right-4 animate-pop">
                <button onClick={() => { SoundSynth.play('pop'); setShowSensei(true); }} className="bg-white text-yellow-600 w-12 h-12 rounded-full flex items-center justify-center hover:bg-yellow-50 shadow-xl border-2 border-yellow-200 transition-all hover:scale-110 active:scale-90 group">
                    <i className="fa-solid fa-robot group-hover:animate-bounce"></i>
                </button>
            </div>

            {showSensei && <ChatSensei context={currentStep.type === 'theory' || currentStep.type === 'boss' ? (currentStep.content || "") : (currentStep.question || "")} onClose={() => setShowSensei(false)} />}

            {/* Footer Control */}
            <div className={`p-6 border-t-2 ${showResult ? (isCorrect ? 'bg-green-500' : 'bg-red-500') : 'bg-white border-yellow-50'}`}>
                <div className="max-w-2xl mx-auto flex justify-between items-center">
                    {showResult ? (
                        <div className="flex gap-4 items-center text-white animate-pop">
                            <div className="w-14 h-14 bg-white/20 rounded-2xl flex items-center justify-center text-3xl border-2 border-white/40">
                                <i className={`fa-solid ${isCorrect ? 'fa-check' : 'fa-bolt'}`}></i>
                            </div>
                            <div>
                                <div className="font-black text-xl uppercase tracking-tighter">{isCorrect ? "龙魂共鸣！" : "灵力紊乱..."}</div>
                                <div className="text-sm opacity-80">{isCorrect ? "你已经掌握了这项奥义。" : "别灰心，反复修习乃是必经之路。"}</div>
                            </div>
                        </div>
                    ) : <div className="flex-1"></div>}

                    <div className="flex-1"></div>

                    {currentStep.type === 'quiz' && !showResult ? (
                        <button onClick={handleQuizCheck} disabled={selectedOption === null} className="px-10 py-4 rounded-2xl font-black text-yellow-800 uppercase tracking-widest bg-yellow-400 hover:bg-yellow-500 border-b-4 border-yellow-600 disabled:opacity-50 shadow-xl active:translate-y-1 active:border-b-0 transition-all">检查答案</button>
                    ) : (currentStep.type === 'theory' || currentStep.type === 'boss' || showResult) ? (
                        <button onClick={handleContinue} className={`px-10 py-4 rounded-2xl font-black uppercase tracking-widest border-b-4 shadow-xl active:translate-y-1 active:border-b-0 transition-all ${showResult ? 'bg-white text-gray-800 border-gray-300' : 'bg-yellow-400 text-yellow-800 border-yellow-600 hover:bg-yellow-500'}`}>
                            继续前进
                        </button>
                    ) : null}
                </div>
            </div>
        </div>
    );
};

const App = () => {
  const [view, setView] = useState<'world' | 'week' | 'lesson'>('world');
  const [selectedWeekId, setSelectedWeekId] = useState<number | null>(null);
  const [selectedDayId, setSelectedDayId] = useState<number | null>(null);

  const [unlockedWeek, setUnlockedWeek] = useState(1);
  const [collectedBalls, setCollectedBalls] = useState(0);
  const [completedDays, setCompletedDays] = useState(0);
  const [showConfetti, setShowConfetti] = useState(false);

  const handleSelectWeek = (id: number) => { setSelectedWeekId(id); setView('week'); };
  const handleBackToWorld = () => { setView('world'); setSelectedWeekId(null); };
  const handlePlayDay = (dayId: number) => { setSelectedDayId(dayId); setView('lesson'); };
  const handleLessonExit = () => { setView('week'); setSelectedDayId(null); };

  const handleUnlockAll = () => {
    setUnlockedWeek(7);
    setCollectedBalls(6);
    setCompletedDays(7);
    setShowConfetti(true);
    setTimeout(() => setShowConfetti(false), 3000);
  };

  const handleLessonComplete = () => {
    // Basic logic for progression
    if (selectedWeekId === unlockedWeek && selectedDayId === completedDays + 1) {
        const newCompleted = completedDays + 1;
        setCompletedDays(newCompleted);
        const currentWeekDays = ALL_CURRICULUM[unlockedWeek]?.length || 0;
        if (newCompleted === currentWeekDays) {
            setCollectedBalls(prev => Math.min(prev + 1, 7));
            if (unlockedWeek < WEEKS.length) {
                setUnlockedWeek(prev => prev + 1);
                setCompletedDays(0);
            }
            setShowConfetti(true); 
            setTimeout(() => setShowConfetti(false), 5000);
        }
    }
    setView('week'); setSelectedDayId(null);
  };

  return (
    <div className="font-sans bg-yellow-50 min-h-screen select-none text-gray-900 selection:bg-yellow-200">
        {showConfetti && <Confetti />}
        {view === 'world' && <WorldMap unlockedWeek={unlockedWeek} onSelectWeek={handleSelectWeek} collectedBalls={collectedBalls} onUnlockAll={handleUnlockAll} />}
        {view === 'week' && selectedWeekId && <WeekLevelView weekId={selectedWeekId} completedDays={completedDays} onPlayDay={handlePlayDay} onBack={handleBackToWorld} />}
        {view === 'lesson' && selectedWeekId && selectedDayId && <LessonEngine weekId={selectedWeekId} dayId={selectedDayId} onComplete={handleLessonComplete} onExit={handleLessonExit} />}
    </div>
  );
};

const root = createRoot(document.getElementById('root')!);
root.render(<App />);

