        <div className="flex-1 overflow-y-auto p-4 space-y-4 bg-yellow-50/30">
          {messages.map((m, i) => (
            <div key={i} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'} animate-slide-up`}>
              <div className={`max-w-[85%] p-4 rounded-2xl shadow-sm ${m.role === 'user' ? 'bg-yellow-500 text-white rounded-tr-none' : 'bg-white border border-yellow-200 text-gray-800 rounded-tl-none'}`}>{m.text}</div>
