          className="absolute top-4 right-4 bg-white/90 text-yellow-600 w-12 h-12 rounded-full flex items-center justify-center shadow-lg active:scale-95 border border-yellow-200"
          title="魔法全开"
        >
          <i className="fa-solid fa-wand-sparkles text-xl"></i>
