        <svg className="absolute inset-0 w-full h-full pointer-events-none" viewBox="0 0 100 100" preserveAspectRatio="none">
            <path d="M50,0 Q10,25 50,45 T50,90" fill="none" stroke="rgba(255,255,255,0.4)" strokeWidth="4" strokeDasharray="8,8" />
        </svg>
        <div className="h-full flex flex-col justify-around py-4">
            {WEEKS.map((week, index) => {
                const isUnlocked = week.id <= unlockedWeek;
                const isCompleted = week.id < unlockedWeek;
                const alignClass = index % 2 === 0 ? 'items-start' : 'items-end';
